import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.util.Scanner;

public class SecurePathTraversal {
    private static final String BASE_PATH = "/path/to/directory/";

    public static void main(String[] args) throws IOException {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter file name: ");
        String fileName = scanner.next();

        File requestedFile = new File(BASE_PATH + fileName);

        if (requestedFile.getCanonicalPath().startsWith(new File(BASE_PATH).getCanonicalPath())) {
            FileInputStream fis = new FileInputStream(requestedFile);
            int content;
            while ((content = fis.read()) != -1) {
                System.out.print((char) content);
            }
            fis.close();
        } else {
            System.out.println("Access to this file is not allowed.");
        }
    }
}

